import Vue from 'vue'
import Vuex from 'vuex'
import VueRouter from 'vue-router'
import dynamicRouter from "@/router/dynamicRouter.js";
import HomeView from '../views/HomeView.vue'
import Error404 from '../views/errorpage/error404.vue'
import LeaveMessage from '../views/contact/LeaveMessage.vue'

import {listSubParentCategory} from "@/api/geekplus/geekplus";

Vue.use(VueRouter)

/* Layout */
import Layout from '@/layout'

//设置type表示页面是菜单类型还是页面，还是跳转的页面
const routes = [
  {
    path: '',
    name: 'layout',
    component: Layout,
    //meta: { title: '首页', icon: '' },
    type: 'layout',
    //hidden:true,
    children:[
      {
        path: '/',
        name: 'home',
        component: HomeView,
        meta: { title: '首页', icon: '' },
        type: 'menu',
        children:[]
      },
      {
        path: '/blogArtices',
        name: 'blog',
        meta: { title: '编程技术', icon: 'fa-home' },
        component: (resolve) => require(['../views/categorypage/BlogPage.vue'],resolve),
        type: 'menu',
        children:[]
      },
      {
        path: '/techArtices',
        name: 'tech',
        meta: { title: '科技前沿', icon: 'fa-home' },
        component: (resolve) => require(['@/views/categorypage/TechPage.vue'],resolve),
        type: 'menu',
        children:[]
      },
      {
        path: '/resourceList',
        name: 'resource',
        meta: { title: '福利资源', icon: 'fa-home' },
        component: () => import(/* webpackChunkName: "about" */'@/views/categorypage/BlogPage.vue'),
        type: 'menu',
        children:[]
      },
      {
        path: '/lifeArticles',
        name: 'myLife',
        meta: { title: '生活随笔', icon: 'fa-home' },
        component: () => import(/* webpackChunkName: "about" */'@/views/categorypage/BlogPage.vue'),
        type: 'menu',
        children:[]
      },
      {
        path: '/leaveMessage',
        name: 'message',
        meta: { title: '留言给我', icon: 'fa-home' },
        component: LeaveMessage,//() => import(/* webpackChunkName: "about" */''),
        type: 'menu',
        children:[]
      },
      {
        path: '/about',
        name: 'about',
        // route level code-splitting
        // this generates a separate chunk (about.[hash].js) for this route
        // which is lazy-loaded when the route is visited.
        component: (resolve) => require(['../views/about/AboutUS.vue'],resolve),
        //component: () => import(/* webpackChunkName: "about" */ '../views/about/AboutUS.vue'),
        meta: { title: '关于', icon: '' },
        type: 'menu',
        children:[]
      },
      {
        path: '/search',
        name: 'search',
        meta: { title: '搜索详情页', icon: 'fa-home' },
        component: (resolve) => require(['@/views/categorypage/SearchResult.vue'],resolve),
        type: 'page',
        hidden: true
      },
      {
        path: '/article/:articleId',
        name: 'article',
        meta: { title: '文章详情页', icon: 'fa-home' },
        component: (resolve) => require(['@/views/article/BlogContent.vue'],resolve),
        type: 'page',
        hidden: true
      },
      {
        path: '/general',
        name: 'article',
        meta: { title: '文章详情页', icon: 'fa-home' },
        component: (resolve) => require(['@/views/article/GeneralContent.vue'],resolve),
        type: 'page',
        hidden: true
      },
    ]
  },
  {
    path: '/chatgpt',
    name: 'ChatGPT',
    meta: { title: 'ChatGPT智能助手', icon: 'fa-home' },
    component: (resolve) => require(['@/views/chatgpt/index.vue'],resolve),
    type: 'page',
    hidden: true
  },
  {
    path: '/honeyComb',
    name: 'honeyComb',
    meta: { title: '蜂窝结构', icon: 'fa-home' },
    component: (resolve) => require(['../components/HoneyComb.vue'],resolve),
    type: 'page',
    hidden:true
  },
  {
    path: '/404',
    name: 'error',
    component: Error404,
    meta: { title: '404', icon: '' },
    type: 'error',
    hidden: true
  },
  {
    path: '/403',
    name: 'error',
    component: (resolve) => require(['@/views/errorpage/error403.vue'],resolve),
    meta: { title: '403', icon: '' },
    type: 'error',
    hidden: true
  },
  //这个*匹配必须放在最后，将改路由配置放到所有路由的配置信息的最后，否则会其他路由path匹配造成影响。     
  {
    path: '*',
    redirect: '/404',
    type: 'error',
    hidden: true
  }
]
// routerPackag(routers) {
//   let accessedRouters = routers.filter(router => {
//       if (router.component === "Layout") {
//           // Layout组件特殊处理
//           router.component = Layout;
//       } else {
//           //处理组件---重点
//           router.component = this.loadView(router.component);
//       }
//       //存在子集
//       if (router.children && router.children.length) {
//           router.children = this.routerPackag(router.children);
//       }
//       return true;
//   });
//   return accessedRouters;
// },
// loadView(view) {
//     // 路由懒加载
//     return () => import(`@/${view}`);
// }
const router = new VueRouter({
  // linkActiveClass: 'active',
  // linkExactActiveClass: 'active',
  mode: 'history',
  scrollBehavior: () => ({ y: 0 }),
  //base: process.env.VUE_APP_BASE_API,
  routes
})
// const store = new Vuex.Store({
//   modules: {
//     routers: routes,
//   },

//   // 数据持久化
//   plugins: [createPersistedState({
//     //key是存储数据的键名
//     key: 'routersData',
//     //paths是存储state中的那些数据，如果是模块下具体的数据需要加上模块名称，如user.token  
//     paths: ["routers.routers"]
//   })]
// })
//beforeEach每次进行路由跳转时都会执行
/**
 * 避免循环执行
 */
let newRoutes = null;
router.beforeEach((to, from, next) => {
  // 判断是否是登录界面
  if (to.path != '/') {
    // 从获取store中Token
    if (getToken()) {
      // 刷新动态路由丢失
      if (!newRoutes) {
        // 调用API获取动态路由
        getRouter().then(res => {
          res.data.data.forEach(element => {
            // 重要：赋值给变量
            let value = element.component;
            element.component = function component(resolve) {
              require(["@/views" + value], resolve);
            };
          });
          dynamicRouter.routes[0].children = res.data.data;
          newRoutes = dynamicRouter.routes;
          // 添加路由数据
          router.addRoutes(newRoutes);
          next({ ...to, replace: true });
        });
      } else {
        next()
      }
    }else{
      next("/");
    }
  } else {
    // 如果是登录界面放行
    next();
  }
});
export default router
